import { defineComponentStyle } from "@yamada-ui/react"

export const simpleGridStyle = defineComponentStyle({})

export type SimpleGridStyle = typeof simpleGridStyle

import { page, render } from "#test/browser"
import { SimpleGrid } from "./simple-grid"

const getDeclaredGridTemplateColumns = () => {
  const element = page.getByText("SimpleGrid").element()

  for (const sheet of Array.from(document.styleSheets).reverse()) {
    let rules: CSSRuleList

    try {
      rules = sheet.cssRules
    } catch {
      continue
    }

    for (const rule of Array.from(rules).reverse()) {
      if (!(rule instanceof CSSStyleRule)) continue

      try {
        if (!element.matches(rule.selectorText)) continue
      } catch {
        continue
      }

      if (rule.style.gridTemplateColumns) return rule.style.gridTemplateColumns
    }
  }

  return getComputedStyle(element).gridTemplateColumns
}

const getComputedGridTemplateColumns = () =>
  getComputedStyle(page.getByText("SimpleGrid").element()).gridTemplateColumns

describe("<SimpleGrid />", () => {
  test("applies `minChildWidth` correctly", async () => {
    await render(<SimpleGrid minChildWidth="200px">SimpleGrid</SimpleGrid>)
    const gridTemplateColumns = getDeclaredGridTemplateColumns()
    expect(gridTemplateColumns).toMatch(
      /^repeat\(auto-fit,\s*minmax\(var\(--sizes200px,\s*200px\),\s*1fr\)\)$/,
    )
  })

  test("applies `minChildWidth` with number value correctly", async () => {
    await render(<SimpleGrid minChildWidth={200}>SimpleGrid</SimpleGrid>)
    const gridTemplateColumns = getDeclaredGridTemplateColumns()
    expect(gridTemplateColumns).toMatch(
      /^repeat\(auto-fit,\s*minmax\(var\(--sizes200,\s*200\),\s*1fr\)\)$/,
    )
    expect(getComputedGridTemplateColumns()).toMatch(/\d+px/)
  })

  test("applies `minChildWidth` takes precedence over `columns`", async () => {
    await render(
      <SimpleGrid columns={2} minChildWidth="100px">
        SimpleGrid
      </SimpleGrid>,
    )
    const gridTemplateColumns = getDeclaredGridTemplateColumns()
    expect(gridTemplateColumns).toMatch(/auto-fit/)
    expect(gridTemplateColumns).not.toMatch(/repeat\(2,/)
  })

  test("applies `columns` correctly", async () => {
    await render(<SimpleGrid columns={3}>SimpleGrid</SimpleGrid>)
    const gridTemplateColumns = getDeclaredGridTemplateColumns().trim()
    expect(gridTemplateColumns).toMatch(/^repeat\(3,\s*minmax\(0px,\s*1fr\)\)$/)
  })
})

"use client"

import type {
  CSSProps,
  StyleValue,
  ThemeProps,
  WithoutThemeProps,
} from "@yamada-ui/react"
import type { GridProps } from "../grid"
import type { SimpleGridStyle } from "./simple-grid.style"
import { useMemo } from "react"
import { createComponent, replaceObject } from "@yamada-ui/react"
import { Grid } from "../grid"
import { simpleGridStyle } from "./simple-grid.style"

export interface SimpleGridProps
  extends
    Omit<WithoutThemeProps<GridProps, SimpleGridStyle>, "columns">,
    ThemeProps<SimpleGridStyle> {
  /**
   * The number of columns.
   */
  columns?: StyleValue<number>
  /**
   * The width at which child elements will break into columns.
   * Pass a number for pixel values or a string for any other valid CSS length.
   */
  minChildWidth?: CSSProps["minWidth"]
}

const {
  PropsContext: SimpleGridPropsContext,
  usePropsContext: useSimpleGridPropsContext,
  withContext,
} = createComponent<SimpleGridProps, SimpleGridStyle>(
  "simple-grid",
  simpleGridStyle,
)

export { SimpleGridPropsContext, useSimpleGridPropsContext }

/**
 * `SimpleGrid` is a component that makes `Grid` simpler and more user-friendly.
 *
 * @see https://yamada-ui.com/docs/components/simple-grid
 */
export const SimpleGrid = withContext<"div", SimpleGridProps>(Grid)(
  undefined,
  ({ columns, minChildWidth, ...rest }) => {
    const templateColumns = useMemo(() => {
      if (minChildWidth) {
        return replaceObject(minChildWidth, (value) => {
          return value != null
            ? `repeat(auto-fit, minmax({sizes.${value}, ${value}}, 1fr))`
            : undefined
        })
      } else {
        return replaceObject(columns, (value) =>
          value != null ? `repeat(${value}, minmax(0, 1fr))` : undefined,
        )
      }
    }, [minChildWidth, columns])

    return { templateColumns, ...rest }
  },
)
